// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./Field.sol";

/// @title 链上直接执行 FFT 电路（与 Python 一致：加法树，omega=1）
/// @notice 计算量 O(n log n)，gas 随 n 增长较快
contract FFTDirect {
    using Field for uint256;

    /// @notice 执行与 Python build_fft_circuit 一致的“FFT”：log(n) 层，每层 next[i] = prev[2i] + prev[2i+1]，最终输出为所有输入之和
    /// @param input 长度为 2^k 的输入
    function fft(uint256[] calldata input) external pure returns (uint256 output) {
        uint256 n = input.length;
        require(n >= 1 && (n & (n - 1)) == 0, "FFTDirect: n must be power of 2");

        uint256[] memory cur = new uint256[](n);
        for (uint256 i = 0; i < n; i++) {
            cur[i] = Field.mod(input[i]);
        }

        uint256 size = n;
        while (size > 1) {
            uint256 half = size / 2;
            for (uint256 i = 0; i < half; i++) {
                cur[i] = cur[i].add(cur[i + half]);
            }
            size = half;
        }
        return cur[0];
    }

    /// @notice 返回执行 FFT 的 gas 使用量（通过内部调用测量）
    function fftGas(uint256[] calldata input) external returns (uint256 gasUsed) {
        uint256 start = gasleft();
        this.fft(input);
        return start - gasleft();
    }
}

