// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./Field.sol";

/// @title FFT 电路 GKR 证明验证合约
/// @notice 验证 GKR proof，支持完整验证（带 input）与 IPFS 优化（仅 input 承诺 + proof 中的 input MLE 值）
contract FFTVerifier {
    using Field for uint256;

    // 与 Python 一致的 Fiat-Shamir
    function _challenge(
        uint256 claimOrState,
        bool first,
        uint256 g0,
        uint256 g1
    ) internal pure returns (uint256 newState) {
        uint256 data = first ? claimOrState : claimOrState;
        data = data.add(g0.mul(1000000)).add(g1);
        newState = data.mul(2654435761).add(2246822507);
        return newState >= Field.PRIME ? newState % Field.PRIME : newState;
    }

    /// @notice 稀疏 FFT wiring MLE: W~(r,a,b)，point = [r (g_vars), a (ab_vars), b (ab_vars)]
    function _wiringMleSparse(
        uint256[] memory point,
        uint256 gVars,
        uint256 abVars
    ) internal pure returns (uint256) {
        require(
            point.length >= gVars + 2 * abVars,
            "FFTVerifier: point too short"
        );
        uint256 prefixSum = 1;
        for (uint256 i = 0; i < gVars; i++) {
            uint256 rv = point[i];
            uint256 av = point[gVars + i];
            uint256 bv = point[gVars + abVars + i];
            uint256 term1 = rv.mul(av).mul(bv);
            uint256 term0 = (Field.PRIME - rv + 1).mul(Field.PRIME - av + 1).mul(Field.PRIME - bv + 1);
            prefixSum = prefixSum.mul(term1.add(term0));
        }
        if (abVars <= gVars) {
            if (gVars > 0 && point[gVars - 1] != 0) return 0;
            uint256 eq0a = gVars > 0 ? (Field.PRIME - point[gVars + gVars - 1] + 1) % Field.PRIME : 1;
            uint256 eq1b = gVars > 0 ? point[gVars + abVars + gVars - 1] : 0;
            return prefixSum.mul(eq0a).mul(eq1b);
        }
        uint256 eq0ag = (Field.PRIME - point[gVars + gVars] + 1) % Field.PRIME;
        uint256 eq1bg = point[gVars + abVars + gVars];
        uint256 suffix = eq0ag.mul(eq1bg);
        for (uint256 i = gVars + 1; i < abVars; i++) {
            suffix = suffix.mul((Field.PRIME - point[gVars + i] + 1) % Field.PRIME);
            suffix = suffix.mul((Field.PRIME - point[gVars + abVars + i] + 1) % Field.PRIME);
        }
        return prefixSum.mul(suffix);
    }

    /// @notice 输入层 MLE 在 point 处的值: sum_i input[i] * chi_i(point)
    function _inputMleAt(
        uint256[] calldata input,
        uint256[] memory point
    ) internal pure returns (uint256) {
        uint256 k = point.length;
        uint256 n = 1 << k;
        require(input.length == n, "FFTVerifier: input length");
        uint256 sum = 0;
        for (uint256 i = 0; i < n; i++) {
            uint256 chi = 1;
            for (uint256 j = 0; j < k; j++) {
                uint256 bit = (i >> (k - 1 - j)) & 1;
                chi = chi.mul(bit == 1 ? point[j] : (Field.PRIME - point[j] + 1));
            }
            sum = sum.add(Field.mod(input[i]).mul(chi));
        }
        return sum;
    }

    /// @notice 递归求 layer MLE（FFT 递推）；nextPoint = last nextVars of (point || bit）
    function _layerMleRecursive(
        uint256 layerIdx,
        uint256[] memory point,
        uint256[] calldata input,
        uint256[] memory layerNumVars
    ) internal pure returns (uint256) {
        uint256 numVars = layerNumVars[layerIdx];
        require(point.length == numVars, "FFTVerifier: point len");
        if (layerIdx == layerNumVars.length - 1) {
            return _inputMleAt(input, point);
        }
        uint256 nextVars = layerNumVars[layerIdx + 1];
        uint256 concatLen = numVars + 1;
        uint256[] memory p0 = new uint256[](nextVars);
        uint256[] memory p1 = new uint256[](nextVars);
        for (uint256 j = 0; j < nextVars; j++) {
            uint256 srcIdx;
            if (concatLen >= nextVars) {
                srcIdx = concatLen - nextVars + j;
                p0[j] = srcIdx < numVars ? point[srcIdx] : 0;
                p1[j] = srcIdx < numVars ? point[srcIdx] : 1;
            } else {
                if (j < nextVars - concatLen) {
                    p0[j] = 0;
                    p1[j] = 0;
                } else {
                    uint256 i = j - (nextVars - concatLen);
                    p0[j] = i < numVars ? point[i] : 0;
                    p1[j] = i < numVars ? point[i] : 1;
                }
            }
        }
        return _layerMleRecursive(layerIdx + 1, p0, input, layerNumVars)
            .add(_layerMleRecursive(layerIdx + 1, p1, input, layerNumVars));
    }

    /// @notice 完整验证：需要传入 input，验证 proof 并检查最后一层与 input MLE 一致
    /// @param input 长度为 n 的输入（n 为 2 的幂）
    /// @param output 声称的电路输出
    /// @param g0 g1 g2 所有 sumcheck 轮的系数（按层顺序拼接）
    /// @param roundCounts 每层 sumcheck 的轮数，如 n=128 时为 [2,4,6,8,10,12,14]
    function verifyFull(
        uint256[] calldata input,
        uint256 output,
        uint256[] calldata g0,
        uint256[] calldata g1,
        uint256[] calldata g2,
        uint256[] calldata roundCounts
    ) external pure returns (bool) {
        uint256 n = input.length;
        require(n >= 2 && (n & (n - 1)) == 0, "FFTVerifier: n not power of 2");
        uint256 numLayers = 0;
        for (uint256 t = n; t > 0; t >>= 1) numLayers++;
        require(roundCounts.length == numLayers - 1, "FFTVerifier: roundCounts len");

        uint256[] memory layerNumVars = new uint256[](numLayers);
        for (uint256 i = 0; i < numLayers; i++) {
            uint256 size = 1 << i;
            layerNumVars[i] = size <= 1 ? 1 : _log2(size - 1);
        }

        uint256 globalIdx = 0;
        uint256 currentClaimed = output;
        uint256[] memory currentPoint = new uint256[](layerNumVars[0]);
        for (uint256 i = 0; i < currentPoint.length; i++) currentPoint[i] = 0;

        for (uint256 layerIdx = 0; layerIdx < numLayers - 1; layerIdx++) {
            uint256 rounds = roundCounts[layerIdx];
            require(
                globalIdx + rounds <= g0.length &&
                    g1.length == g0.length &&
                    g2.length == g0.length,
                "FFTVerifier: proof length"
            );

            uint256 prevVal = g0[globalIdx].add(g1[globalIdx]);
            if (prevVal != currentClaimed) return false;

            bool first = true;
            uint256 state = prevVal;
            uint256[] memory fixed_ = new uint256[](rounds);
            for (uint256 r = 0; r < rounds; r++) {
                uint256 g0r = g0[globalIdx + r];
                uint256 g1r = g1[globalIdx + r];
                uint256 g2r = g2[globalIdx + r];
                if (g0r.add(g1r) != prevVal) return false;
                uint256 rVal = _challenge(state, first, g0r, g1r);
                first = false;
                state = rVal;
                prevVal = Field.lagrange3(g0r, g1r, g2r, rVal);
                fixed_[r] = rVal;
            }
            globalIdx += rounds;

            uint256 s = rounds / 2; // ab_vars
            uint256 gVars = layerNumVars[layerIdx];
            uint256 abVars = s;
            uint256[] memory point = new uint256[](gVars + 2 * abVars);
            for (uint256 i = 0; i < gVars; i++) point[i] = currentPoint[i];
            for (uint256 i = 0; i < abVars; i++) {
                point[gVars + i] = fixed_[i];
                point[gVars + abVars + i] = fixed_[s + i];
            }
            uint256 addVal = _wiringMleSparse(point, gVars, abVars);
            uint256[] memory aPoint = new uint256[](abVars);
            uint256[] memory bPoint = new uint256[](abVars);
            for (uint256 i = 0; i < abVars; i++) {
                aPoint[i] = fixed_[i];
                bPoint[i] = fixed_[s + i];
            }
            uint256 va = _layerMleRecursive(layerIdx + 1, aPoint, input, layerNumVars);
            uint256 vb = _layerMleRecursive(layerIdx + 1, bPoint, input, layerNumVars);
            uint256 finalVal = addVal.mul(va.add(vb));
            if (prevVal != finalVal) return false;

            uint256 nextS = layerNumVars[layerIdx + 1];
            uint256 data = 0;
            for (uint256 k = 0; k < s && k < abVars; k++) {
                data = data.add(aPoint[k].mul(_pow2(k * 32)));
                data = data.add(bPoint[k].mul(_pow2((s + k) * 32)));
            }
            uint256 hashVal = data.mul(2654435761).add(2246822507);
            hashVal = hashVal >= Field.PRIME ? hashVal % Field.PRIME : hashVal;
            currentPoint = new uint256[](nextS);
            for (uint256 i = 0; i < nextS; i++) {
                uint256 coord = hashVal.mul(1000000).add(i);
                currentPoint[i] = coord >= Field.PRIME ? coord % Field.PRIME : coord;
            }
            currentClaimed = _layerMleRecursive(layerIdx + 1, currentPoint, input, layerNumVars);
        }

        uint256 computed = _inputMleAt(input, currentPoint);
        return computed == currentClaimed;
    }

    /// @notice IPFS 优化：不传 input，只传 inputCommitment（如 keccak256(ipfsCID)）与 proof（含每层 v_a,v_b 及每层下一层的 claimed 值）
    /// @param vaVb 每层 (v_a, v_b) 按层顺序拼接，长度 2*(numLayers-1)
    /// @param nextClaimed 每层 sumcheck 后下一层的 claimed 值，长度 numLayers-1；最后一项为 input MLE 在最终挑战点的值
    /// @dev 不验证 input 与 commitment 的绑定；用于节省 input 的 calldata 与链上 input MLE 计算的 gas
    function verifyWithIPFS(
        bytes32 inputCommitment,
        uint256 output,
        uint256[] calldata g0,
        uint256[] calldata g1,
        uint256[] calldata g2,
        uint256[] calldata roundCounts,
        uint256[] calldata vaVb,
        uint256[] calldata nextClaimed
    ) external pure returns (bool) {
        uint256 numLayers = roundCounts.length + 1;
        require(vaVb.length >= 2 * (numLayers - 1), "FFTVerifier: vaVb len");
        require(nextClaimed.length >= numLayers - 1, "FFTVerifier: nextClaimed len");
        uint256[] memory layerNumVars = new uint256[](numLayers);
        for (uint256 i = 0; i < numLayers; i++) {
            uint256 size = 1 << i;
            layerNumVars[i] = size <= 1 ? 1 : _log2(size - 1);
        }

        uint256 globalIdx = 0;
        uint256 currentClaimed = output;
        uint256[] memory currentPoint = new uint256[](layerNumVars[0]);
        for (uint256 i = 0; i < currentPoint.length; i++) currentPoint[i] = 0;
        uint256 vaVbIdx = 0;

        for (uint256 layerIdx = 0; layerIdx < numLayers - 1; layerIdx++) {
            uint256 rounds = roundCounts[layerIdx];
            require(globalIdx + rounds <= g0.length, "FFTVerifier: proof length");

            uint256 prevVal = g0[globalIdx].add(g1[globalIdx]);
            if (prevVal != currentClaimed) return false;

            bool first = true;
            uint256 state = prevVal;
            uint256[] memory fixed_ = new uint256[](rounds);
            for (uint256 r = 0; r < rounds; r++) {
                uint256 g0r = g0[globalIdx + r];
                uint256 g1r = g1[globalIdx + r];
                uint256 g2r = g2[globalIdx + r];
                if (g0r.add(g1r) != prevVal) return false;
                uint256 rVal = _challenge(state, first, g0r, g1r);
                first = false;
                state = rVal;
                prevVal = Field.lagrange3(g0r, g1r, g2r, rVal);
                fixed_[r] = rVal;
            }
            globalIdx += rounds;

            uint256 s = rounds / 2;
            uint256 gVars = layerNumVars[layerIdx];
            uint256 abVars = s;
            uint256[] memory point = new uint256[](gVars + 2 * abVars);
            for (uint256 i = 0; i < gVars; i++) point[i] = currentPoint[i];
            for (uint256 i = 0; i < abVars; i++) {
                point[gVars + i] = fixed_[i];
                point[gVars + abVars + i] = fixed_[s + i];
            }
            uint256 addVal = _wiringMleSparse(point, gVars, abVars);
            uint256 va = vaVb[vaVbIdx];
            uint256 vb = vaVb[vaVbIdx + 1];
            vaVbIdx += 2;
            uint256 finalVal = addVal.mul(va.add(vb));
            if (prevVal != finalVal) return false;

            uint256[] memory aPoint = new uint256[](abVars);
            uint256[] memory bPoint = new uint256[](abVars);
            for (uint256 i = 0; i < abVars; i++) {
                aPoint[i] = fixed_[i];
                bPoint[i] = fixed_[s + i];
            }
            uint256 nextS = layerNumVars[layerIdx + 1];
            uint256 data = 0;
            for (uint256 k = 0; k < s && k < abVars; k++) {
                data = data.add(aPoint[k].mul(_pow2(k * 32)));
                data = data.add(bPoint[k].mul(_pow2((s + k) * 32)));
            }
            uint256 hashVal = data.mul(2654435761).add(2246822507);
            hashVal = hashVal >= Field.PRIME ? hashVal % Field.PRIME : hashVal;
            currentPoint = new uint256[](nextS);
            for (uint256 i = 0; i < nextS; i++) {
                currentPoint[i] = hashVal.mul(1000000).add(i);
                if (currentPoint[i] >= Field.PRIME) currentPoint[i] %= Field.PRIME;
            }
            currentClaimed = nextClaimed[layerIdx];
        }
        return true;
    }

    function _log2(uint256 x) internal pure returns (uint256 r) {
        r = 0;
        while (x > 0) {
            x >>= 1;
            r++;
        }
        return r;
    }

    function _pow2(uint256 k) internal pure returns (uint256) {
        return Field.pow(2, k);
    }
}

