// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/// @title 与 Python GKR 一致的有限域 (Starknet PRIME)
library Field {
    // p = 2^251 + 17*2^192 + 1
    uint256 internal constant PRIME = 0x800000000000011000000000000000000000000000000000000000000000001;

    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        return _mod(a + b);
    }

    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        return _mod(PRIME + a - b);
    }

    function mul(uint256 a, uint256 b) internal pure returns (uint256) {
        return mulmod(a, b, PRIME);
    }

    function _mod(uint256 x) internal pure returns (uint256) {
        if (x >= PRIME) return x % PRIME;
        return x;
    }

    function mod(uint256 x) internal pure returns (uint256) {
        return _mod(x);
    }

    /// @notice 模逆 a^(-1) mod p，使用费马小定理 a^(p-2)
    function inv(uint256 a) internal pure returns (uint256) {
        if (a == 0) return 0;
        return pow(a, PRIME - 2);
    }

    function pow(uint256 base, uint256 exp) internal pure returns (uint256) {
        uint256 result = 1;
        base = _mod(base);
        for (; exp > 0; exp >>= 1) {
            if ((exp & 1) != 0) result = mul(result, base);
            base = mul(base, base);
        }
        return result;
    }

    /// @notice 三点 Lagrange 插值 L(x) 使 L(0)=g0, L(1)=g1, L(2)=g2
    function lagrange3(uint256 g0, uint256 g1, uint256 g2, uint256 x) internal pure returns (uint256) {
        uint256 xm1 = sub(x, 1);
        uint256 xm2 = sub(x, 2);
        uint256 invNeg1 = inv(PRIME - 1);
        uint256 invNeg2 = inv(PRIME - 2);
        uint256 inv2 = inv(2);
        uint256 l0 = mul(mul(xm1, xm2), mul(invNeg1, invNeg2));
        uint256 l1 = mul(mul(x, xm2), mul(1, inv(PRIME - 1)));
        uint256 l2 = mul(mul(x, xm1), mul(inv2, 1));
        return add(add(mul(g0, l0), mul(g1, l1)), mul(g2, l2));
    }
}

